import Cookie from 'cookie-universal';
import Axios, { LOGOUT } from '../../Api/Api';

const cookie = Cookie();

// دالة تسجيل الخروج
export async function handleLogout(navigate) {
    try {
        // إرسال طلب Logout للباك إند
        await Axios.post(`/${LOGOUT}`);
    } catch (error) {
        console.error('خطأ في تسجيل الخروج:', error);
    } finally {
        // حذف البيانات من Cookie
        cookie.remove('educational-token');
        cookie.remove('educational-user');
        
        // التوجيه لصفحة Login
        if (navigate) {
            navigate('/login');
        } else {
            window.location.pathname = '/login';
        }
    }
}

// دالة للحصول على المستخدم الحالي
export function getCurrentUser() {
    const userData = cookie.get('educational-user');
    return userData ? JSON.parse(userData) : null;
}
